"use client";

import { useMemo } from "react";
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";
import { Expense } from "@/lib/firebase";

interface DashboardProps {
  expenses: Expense[];
}

const COLORS = ['#8b5cf6', '#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#ec4899'];

export function Dashboard({ expenses }: DashboardProps) {
  const totalSpent = useMemo(() => {
    return expenses.reduce((sum, exp) => sum + exp.amount, 0);
  }, [expenses]);

  const categoryData = useMemo(() => {
    const categories: Record<string, number> = {};
    expenses.forEach((exp) => {
      categories[exp.category] = (categories[exp.category] || 0) + exp.amount;
    });
    return Object.entries(categories)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);
  }, [expenses]);

  const dailyData = useMemo(() => {
    const dates: Record<string, number> = {};
    expenses.forEach((exp) => {
      dates[exp.date] = (dates[exp.date] || 0) + exp.amount;
    });
    return Object.entries(dates)
      .map(([date, amount]) => ({ date, amount }))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .slice(-7); // Last 7 days with activity
  }, [expenses]);

  if (expenses.length === 0) {
    return (
      <div className="glass dark:glass-dark rounded-3xl p-8 text-center text-foreground/70">
        <p>No expenses found yet. Try speaking your first expense above!</p>
      </div>
    );
  }

  return (
    <div className="w-full space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
      
      {/* Total Spent Card */}
      <div className="glass dark:glass-dark rounded-3xl p-6 text-center shadow-lg">
        <h2 className="text-xl text-foreground/80 font-medium">Total Spent</h2>
        <p className="text-4xl font-bold bg-gradient-to-r from-primary-500 to-blue-500 bg-clip-text text-transparent mt-2">
          ${totalSpent.toFixed(2)}
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Category Pie Chart */}
        <div className="glass dark:glass-dark rounded-3xl p-6 shadow-lg">
          <h3 className="text-lg font-medium mb-4">Spending by Category</h3>
          <div className="h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: any) => `$${Number(value).toFixed(2)}`}
                  contentStyle={{ backgroundColor: 'rgba(15, 23, 42, 0.9)', borderRadius: '12px', border: 'none', color: '#fff' }}
                  itemStyle={{ color: '#fff' }}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex flex-wrap gap-2 justify-center mt-4">
             {categoryData.map((cat, i) => (
               <div key={cat.name} className="flex items-center text-xs space-x-1">
                 <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                 <span>{cat.name}</span>
               </div>
             ))}
          </div>
        </div>

        {/* Daily Bar Chart */}
        <div className="glass dark:glass-dark rounded-3xl p-6 shadow-lg">
          <h3 className="text-lg font-medium mb-4">Recent Daily Spending</h3>
          <div className="h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={dailyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} strokeOpacity={0.2} />
                <XAxis dataKey="date" tick={{ fontSize: 12 }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fontSize: 12 }} axisLine={false} tickLine={false} tickFormatter={(val) => `$${val}`} />
                <Tooltip 
                  formatter={(value: any) => `$${Number(value).toFixed(2)}`}
                  cursor={{ fill: 'rgba(255, 255, 255, 0.1)' }}
                  contentStyle={{ backgroundColor: 'rgba(15, 23, 42, 0.9)', borderRadius: '12px', border: 'none', color: '#fff' }}
                  itemStyle={{ color: '#fff' }}
                />
                <Bar dataKey="amount" fill="#8b5cf6" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Recent Expenses List */}
      <div className="glass dark:glass-dark rounded-3xl p-6 shadow-lg">
        <h3 className="text-lg font-medium mb-4">Recent Transactions</h3>
        <div className="space-y-4">
          {expenses.slice(0, 5).map((exp, i) => (
            <div key={exp.id || i} className="flex justify-between items-center p-3 hover:bg-white/5 dark:hover:bg-white/5 rounded-xl transition-colors">
              <div>
                <p className="font-medium text-foreground">{exp.vendor} <span className="text-xs text-foreground/50 ml-2">{exp.category}</span></p>
                <p className="text-sm text-foreground/60">{new Date(exp.date).toLocaleDateString()}</p>
              </div>
              <p className="font-bold text-lg text-primary-500">${exp.amount.toFixed(2)}</p>
            </div>
          ))}
        </div>
      </div>

    </div>
  );
}
